namespace sv_f6d1f0e6319946538f47878c93a3e5cd.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@namespace sv_f6d1f0e6319946538f47878c93a3e5cd.Components.Pages.Chat

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-name"># @Channel.Name</div>
    <div class="channel-description">@Channel.Description</div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnSelected { get; set; }

    private async Task OnClick() => await OnSelected.InvokeAsync(Channel);
}

@namespace sv_f6d1f0e6319946538f47878c93a3e5cd.Components.Pages.Chat

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
}

@namespace sv_f6d1f0e6319946538f47878c93a3e5cd.Components.Pages.Chat

<div class="message-input">
    <textarea @bind="text" @bind:event="oninput" placeholder="@Placeholder"
              @onkeydown="HandleKeyDown" rows="2"></textarea>
    <button class="send-button" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string text = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(text)) return;
        var message = text.Trim();
        text = string.Empty;
        await OnSubmit.InvokeAsync(message);
    }
}

@namespace sv_f6d1f0e6319946538f47878c93a3e5cd.Components.Pages.Chat

<div class="chat-message" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-bar">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => React(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message)">
            @ReplyCount replies
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀 React
            </button>
        </div>

        @if (showEmojiPicker)
        {
            <div class="emoji-picker">
                @foreach (var emoji in commonEmojis)
                {
                    <button class="emoji-option" @onclick="() => React(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task React(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@namespace sv_f6d1f0e6319946538f47878c93a3e5cd.Components.Pages.Chat
@inject IJSRuntime JS

<div class="message-area">
    <div class="message-area-header">
        <h2># @ChannelName</h2>
        <p>@ChannelDescription</p>
    </div>

    <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages...</div>
        }
        @foreach (var message in Messages)
        {
            <ChatMessage Message="message"
                         ReplyCount="GetReplyCount(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")" OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = string.Empty;
    [Parameter] public string ChannelDescription { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference messageListRef;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list').scrollTop");
        if (scrollTop <= 50 && !IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }
}

@namespace sv_f6d1f0e6319946538f47878c93a3e5cd.Components.Pages.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    <div class="thread-root-message">
        <span class="message-author">@RootMessage.Author</span>
        <p>@RootMessage.Content</p>
    </div>

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="message-header">
                    <span class="message-author">@reply.Author</span>
                    <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="message-content">@reply.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread..." ButtonLabel="Reply" OnSubmit="OnSendReply" />
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@page "/chat"
@namespace sv_f6d1f0e6319946538f47878c93a3e5cd.Components.Pages.Chat
@using sv_f6d1f0e6319946538f47878c93a3e5cd.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="chat-main @(threadOpen ? "thread-open" : "")">
        @if (selectedChannel is not null)
        {
            <MessageArea ChannelName="@selectedChannel.Name"
                         ChannelDescription="@selectedChannel.Description"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         IsLoadingMore="isLoadingMore"
                         OnLoadMore="LoadMoreMessages"
                         OnSendMessage="SendMessage"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadOpen && threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadMessages"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private int selectedChannelId;
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = new();
    private bool isLoadingMore;

    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        selectedChannelId = channel.Id;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channel.Id);
        await UpdateThreadReplyCounts();
        CloseThread();
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null || isLoadingMore) return;
        isLoadingMore = true;
        var olderMessages = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        if (olderMessages.Count > 0)
        {
            messages.InsertRange(0, olderMessages);
        }
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var newMessage = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(newMessage);
    }

    private async Task OpenThread(Message message)
    {
        threadRootMessage = message;
        threadMessages = await ChatService.GetThreadAsync(message.Id);
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadMessages.Add(reply);

        // Update reply count
        threadReplyCounts[threadRootMessage.Id] = threadMessages.Count;
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
        // Refresh messages to show updated reactions
