@namespace sv_f6d1f0e6319946538f47878c93a3e5cd.Components.Pages.Chat
@using sv_f6d1f0e6319946538f47878c93a3e5cd.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="chat-main @(threadOpen ? "thread-open" : "")">
        @if (selectedChannel is not null)
        {
            <MessageArea ChannelName="@selectedChannel.Name"
                         ChannelDescription="@selectedChannel.Description"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         IsLoadingMore="isLoadingMore"
                         OnLoadMore="LoadMoreMessages"
                         OnSendMessage="SendMessage"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadOpen && threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadMessages"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private int selectedChannelId;
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = new();
    private bool isLoadingMore;

    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        selectedChannelId = channel.Id;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channel.Id);
        await UpdateThreadReplyCounts();
        CloseThread();
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null || isLoadingMore) return;
        isLoadingMore = true;
        var olderMessages = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        if (olderMessages.Count > 0)
        {
            messages.InsertRange(0, olderMessages);
        }
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var newMessage = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(newMessage);
    }

    private async Task OpenThread(Message message)
    {
        threadRootMessage = message;
        threadMessages = await ChatService.GetThreadAsync(message.Id);
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadMessages.Add(reply);

        // Update reply count
        threadReplyCounts[threadRootMessage.Id] = threadMessages.Count;
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
        // Refresh messages to show updated reactions
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
        }
    }

    private async Task UpdateThreadReplyCounts()
    {
        threadReplyCounts.Clear();
        // Messages with replies are those referenced by other messages' ReplyToId
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        foreach (var rootId in rootIds)
        {
            var thread = await ChatService.GetThreadAsync(rootId);
            if (thread.Count > 0)
            {
                threadReplyCounts[rootId] = thread.Count;
            }
        }
    }
}
"}

