toolArgs.file_text:
.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e5e7eb;
    background: #fafbfc;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #d1d5db;
    border-radius: 8px;
    padding: 10px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #3b82f6;
}

.send-button {
    align-self: flex-end;
    background: #3b82f6;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.send-button:hover:not(:disabled) {
    background: #2563eb;
}

.send-button:disabled {
    background: #93c5fd;
    cursor: not-allowed;
}

