    font-weight: 700;
    font-size: 0.85rem;
    color: #111827;
}

.thread-root-message p {
    margin: 4px 0 0;
    font-size: 0.85rem;
    color: #374151;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.thread-reply .message-header {
    display: flex;
    align-items: baseline;
